sql:
SELECT witness_name, witness_age
FROM crime_witnesses
WHERE reliability_score > 3;

SELECT report_date, description
FROM crime_reports
WHERE report_id = 0;

SELECT suspect_gender, COUNT(*) AS total_suspects
FROM crime_suspects
GROUP BY suspect_gender;

SELECT victim_name, victim_age, statement
FROM crime_victims
WHERE victim_name = 'Bob Williams';

external_knowledge:
- District 1 refers to a specific police district;
- Crime statistics typically include the total number of crimes, crime rate per 100,000 population, reported crimes, solved crimes, and arrests made;
- Investigative details include the names of suspects, victims, and witnesses involved in a crime;
- Users who accessed the records are likely police officers, analysts, or administrative personnel.
